## Implementing top 200 + 200 peaks:

```
best_200 = MinHeap(lambda v: v['pval'])
peaks_200 = []
bins = {}
def bin(v): ...
for v in variants:
  best_200.add(v)
  if len(best_200) > 200:
    v = best_200.pop()
    if v['pval'] > max(p['pval'] for p in peaks_200):
      bin(v)
    elif any(p['chr'] == v['chr'] and abs(p['pos'] - v['pos']) < 500e3 and p['pval'] < v['pval'] for p in peaks_200):
      bin(v)
    else:
      peaks_200 = [p for p in peaks_200 if p['chr'] != v['chr'] or abs(p['pos'] - v['pos']) > 500e3] + [v]
      if len(peaks_200) > 200:
        v = max(peaks_200, lambda p: p['pval'])
        peaks_200.remove(v)
        bin(v)
```

